import customtkinter as ctkfrom app.ui.main_window import MainWindowfrom app.ui.login_window import LoginWindowfrom app.controllers import ArchiveControllerfrom app.database import Base, engine# Initialize databaseBase.metadata.create_all(bind=engine)def main():    # Set the global theme for CustomTkinter to match the dark aesthetic    ctk.set_appearance_mode("dark")    controller = ArchiveController()    # Instantiate the CustomTkinter login window and pass the controller    login_window = LoginWindow(controller)    # Callback function to replace the PyQt signal    def show_main_app(role):        print(f"Logged in as: {role}")        # Destroy the login window, which ends its mainloop        login_window.destroy()        # Instantiate and run the main window        main_window = MainWindow()        # main_window.set_user_role(role)        main_window.mainloop()    # Attach the callback to the login window instance    login_window.on_login_successful = show_main_app    # Start the application loop with the login window    login_window.mainloop()if __name__ == "__main__":    main()